const body = ($input.item.json && $input.item.json.body) || $input.item.json || {};
const secret = body.internal_secret || '';
const expected = process.env.INTERNAL_EMAIL_SECRET || '';
if (!expected || secret !== expected) return { json: { _unauthorized: true, error: 'internal secret required' } };
if (!body.video_render_id) return { json: { _empty: true, error: 'video_render_id required' } };
return { json: { _authorized: true, video_render_id: body.video_render_id } };

const rows = $input.item.json;
const row = Array.isArray(rows) ? rows[0] : rows;
if (!row || !row.id) return { json: { _failed: true, error: 'video_render not found' } };
if (!row.script || !row.script.trim()) return { json: { _failed: true, error: 'script empty' } };
// Map persona+look to HeyGen avatar id. In production these IDs come from
// Mary's HeyGen account once she generates the personas. For now we use
// env vars to allow per-environment override without code change.
const personaLookKey = (row.persona_id || 'james') + '_' + (row.look_id || 'suit');
const envVar = 'HEYGEN_AVATAR_' + personaLookKey.toUpperCase();
const voiceEnvVar = 'HEYGEN_VOICE_' + (row.voice_id || 'james_voice').toUpperCase();
return { json: {
  video_render_id: row.id,
  script: row.script,
  persona_look_key: personaLookKey,
  avatar_env_var: envVar,
  voice_env_var: voiceEnvVar,
  custom_avatar_id: row.heygen_avatar_id || null
} };

const ctx = $('Resolve Avatar IDs').item.json;
const resp = $input.item.json || {};
// HeyGen v2 returns: { error, data: { video_id } }
const heygenVideoId = (resp.data && resp.data.video_id) || resp.video_id || null;
if (!heygenVideoId) {
  return { json: { _failed: true, video_render_id: ctx.video_render_id, error: (resp.error && resp.error.message) || resp.error || 'no_video_id' } };
}
return { json: { video_render_id: ctx.video_render_id, heygen_video_id: heygenVideoId } };
